import{c as t,Q as n,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"How do I create an internal user?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/create-internal-user.md","filePath":"guide/recipes/admin/create-internal-user.md","lastUpdated":1778912818000}'),o={name:"guide/recipes/admin/create-internal-user.md"};function r(i,e,l,c,d,p){return n(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-create-an-internal-user" tabindex="-1">How do I create an internal user? <a class="header-anchor" href="#how-do-i-create-an-internal-user" aria-label="Permalink to &quot;How do I create an internal user?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> only</p></div><p>Internal users are Exto operators with Console access. Inviting one creates the record and sends a sign-in invitation.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Internal Users</strong> in the sidebar.</li><li>Click <strong>Add User</strong>.</li><li>Fill in <strong>First name</strong>, <strong>Last name</strong>, <strong>Email</strong>.</li><li>In the <strong>Roles</strong> section, tick one or more: <ul><li><strong>Platform Admin</strong> — full access.</li><li><strong>Infra Ops</strong> — fleet operations.</li><li><strong>Finance Admin</strong> — billing-only.</li><li><strong>Compliance Admin</strong> — audit-only (read).</li><li><strong>Reader</strong> — view-only.</li><li><strong>Account Manager</strong> — scoped to specific customers.</li><li><strong>QA Admin</strong> — scoped to specific customers <em>and</em> instances.</li></ul></li><li>If you ticked <strong>Account Manager</strong> or <strong>QA Admin</strong>, the scope pickers appear. Pick at least one customer (and at least one instance for QA Admin).</li><li>Click <strong>Send Invite</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The user appears in the table with status <strong>Invited</strong>. They receive an email with a sign-in link. Once they accept, status flips to <strong>Active</strong> and they see only the parts of the Console their roles allow.</p><div class="tip custom-block"><p class="custom-block-title">Multiple roles</p><p>You can union roles — e.g. Account Manager + Finance Admin gives someone scoped customer access plus full finance visibility.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./account-manager-scope">How do I assign Account Manager scope?</a></li><li><a href="./qa-admin-scope">How do I assign QA Admin scope?</a></li><li><a href="./../../concepts/roles-and-permissions">Roles &amp; Permissions reference</a></li></ul>',10)])])}const m=t(o,[["render",r]]);export{g as __pageData,m as default};
